use std::collections::HashMap;

struct MessageBroker {
    name: String,
    isEnabled: bool,
    bufferSize: usize,
    maxRetries: u32,
}

impl MessageBroker {
    fn new(name: &str) -> Self {
        MessageBroker { 
            name: name.to_string(), 
            isEnabled: false, 
            bufferSize: 1024, 
            maxRetries: 3 
        }
    }

    fn withName(self, name: String) -> Self {
        MessageBroker { 
            name: name, 
            ..self 
        }
    }

    fn withEnabled(self, enabled: bool) -> Self {
        MessageBroker { 
            isEnabled: enabled, 
            ..self 
        }
    }

    fn withBufferSize(self, size: usize) -> Self {
        MessageBroker { 
            bufferSize: size, 
            ..self 
        }
    }

    fn withMaxRetries(self, retries: u32) -> Self {
        MessageBroker { 
            maxRetries: retries, 
            ..self 
        }
    }

    fn display_info(&self) {
        println!("--- Broker Info ---");
        println!("Name: {}", self.name);
        println!("Active: {}", if self.isEnabled { "Yes" } else { "No" });
        println!("Buffer Size: {}", self.bufferSize);
        println!("Max Retries: {}", self.maxRetries);
    }
}

fn main() {
    let broker1 = MessageBroker::new("TestPubSub")
        .withName(String::from("FastMessageBus"))
        .withEnabled(true)
        .withBufferSize(4096)
        .withMaxRetries(5);

    let broker2 = MessageBroker::new("LocalCache")
        .withMaxRetries(1); 

    broker1.display_info();
    println!("");
    broker2.display_info();
}

use std::fmt::Write;

struct PeripheralConfig {
    base_addr: u32,
    read_mask: u32,
    write_value: u32,
    enable_gpio: bool,
}

impl PeripheralConfig {
    fn new(base_addr: u32) -> Self {
        PeripheralConfig { 
            base_addr,
            read_mask: 0x0000FFFF,
            write_value: 0xAAAAAAAA,
            enable_gpio: false,
        }
    }

    fn with_register_settings(mut self) -> Self {
        self.write_value = 0xDEADBEEF;
        self
    }

    fn with_clock_gating(mut self) -> Self {
        self.enable_gpio = true;
        self
    }

    fn finalize_setup(&self) -> String {
        let mut output = String::new();
        writeln!(output, "Initializing block at address 0x{:X}", self.base_addr).unwrap();
        writeln!(output, "Reading initial state mask: 0x{:X}", self.read_mask).unwrap();
        writeln!(output, "Applying primary write value: 0x{:X}", self.write_value).unwrap();
        if self.enable_gpio {
            writeln!(output, "Clock gating sequence enabled.").unwrap();
        } else {
            writeln!(output, "Clock gates remain disabled for now.").unwrap();
        }
        output
    }
}

fn main() {
    let final_setup = PeripheralConfig::new(0x40021000)
        .with_register_settings()
        .with_clock_gating();
    println!("{}, {}", "\"", final_setup.finalize_setup());
}

use std::error::Error;
use std::fmt;

struct SensorConfig {
    device_id: String,
    sampling_rate_hz: f64,
    is_active: bool,
    max_payload_bytes: usize,
}

impl SensorConfig {
    fn new(device_id: String) -> Self {
        SensorConfig {
            device_id,
            sampling_rate_hz: 0.1,
            is_active: false,
            max_payload_bytes: 1024,
        }
    }

    fn with_rate(mut self, rate: f64) -> Self {
        SensorConfig {
            device_id: self.device_id.clone(),
            sampling_rate_hz: rate,
            is_active: self.is_active,
            max_payload_bytes: self.max_payload_bytes,
        }
    }

    fn set_status(mut self, active: bool) -> Self {
        SensorConfig {
            device_id: self.device_id.clone(),
            sampling_rate_hz: self.sampling_rate_hz,
            is_active: active,
            max_payload_bytes: self.max_payload_bytes,
        }
    }

    fn finalize(self, payload: usize) -> Self {
        SensorConfig {
            device_id: self.device_id.clone(),
            sampling_rate_hz: self.sampling_rate_hz,
            is_active: self.is_active,
            max_payload_bytes: payload,
        }
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let config = SensorConfig::new("sensor-xyz-123".to_string())
        .with_rate(1.5)
        .set_status(true)
        .finalize(2048);

    println!("Successfully built configuration for: {}", config.device_id);
    println!("Rate set to: {} Hz", config.sampling_rate_hz);

    Ok(())
}

use std::error::Error;
use std::fmt;

struct TaskConfig {
    input_source: String,
    worker_type: String,
    batch_size: usize,
    timeout_ms: u64,
}

impl TaskConfig {
    fn new(input_source: String) -> Self {
        TaskConfig {
            input_source,
            worker_type: "default".to_string(),
            batch_size: 1024,
            timeout_ms: 5000,
        }
    }

    fn with_worker_type(mut self, worker_type: &str) -> Self {
        self.worker_type = worker_type.to_string();
        self
    }

    fn set_batch_size(mut self, batch_size: usize) -> Self {
        self.batch_size = batch_size;
        self
    }

    fn with_timeout(mut self, timeout_ms: u64) -> Self {
        self.timeout_ms = timeout_ms;
        self
    }

    fn build(self) -> Result<Self, Box<dyn Error>> {
        if self.input_source.is_empty() {
            return Err("Input source cannot be empty".into());
        }
        Ok(self)
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let config = TaskConfig::new("s3://bucket/data.json".to_string())
        .with_worker_type(&"gpu_accelerated".to_string()) 
        .set_batch_size(4096) 
        .with_timeout(15000);

    let final_config = config.build()?;
    println!("Successfully built task configuration:");
    println!("  Input: {}", final_config.input_source);
    println!("  Worker Type: {}", final_config.worker_type);
    println!("  Batch Size: {}", final_config.batch_size);
    println!("  Timeout: {}ms", final_config.timeout_ms);

    Ok(())
}

use std::io;
use std::time::Duration;
use std::thread;

struct PeripheralBuilder {
    base_address: u32,
}

impl PeripheralBuilder {
    fn new(base_address: u32) -> Self {
        PeripheralBuilder { base_address }
    }

    fn set_interrupt_mask(&mut self, mask_value: u32) -> &mut Self {
        let register_addr = self.base_address + 0x10;
        unsafe {
            std::ptr::write_volatile(register_addr as *mut u32, mask_value);
        }
        self
    }

    fn write_control_sequence(&mut self, values: &[u32]) -> &mut Self {
        let control_reg = self.base_address + 0x20;
        unsafe {
            for (i, &val) in values.iter().enumerate() {
                std::ptr::write_volatile((control_reg + i as u32 * 4) as *mut u32, val);
            }
        }
        self
    }

    fn enable_clock(&mut self) -> &mut Self {
        let clock_gate = self.base_address + 0x04;
        unsafe {
            std::ptr::write_volatile(clock_gate as *mut u32, 1);
        }
        self
    }

    fn build(&self) -> io::Result<()> {
        println!("Peripheral initialization sequence started.");
        Ok(())
    }
}

fn main() -> io::Result<()> {
    let mut builder = PeripheralBuilder::new(0xFF00_0000);
    builder.set_interrupt_mask(0b1010)
           .write_control_sequence(&[0xDEADBEEF, 0xCAFEBABE])
           .enable_clock();

    if let Err(e) = builder.build() {
        eprintln!("Failed to build peripheral: {}", e);
    } else {
        println!("Peripheral initialized successfully.");
    }

    thread::sleep(Duration::from_millis(10));
    Ok(())
}
